use ritual_metrics;

pub fn send_transactions_hashes(&self, peer_id: PeerId, msg: NewPooledTransactionHashes) {
    match &msg {
        NewPooledTransactionHashes::Eth66(hashes) => {
            for hash in hashes.0.iter() {
                ritual_metrics::tx::log_p2p_tx_announce(hash, &peer_id, "eth66");
            }
        }
        NewPooledTransactionHashes::Eth68(hashes) => {
            for hash in hashes.hashes.iter() {
                ritual_metrics::tx::log_p2p_tx_announce(hash, &peer_id, "eth68");
            }
        }
    }
    self.send_message(NetworkHandleMessage::SendPooledTransactionHashes { peer_id, msg })
}
